import { z } from 'zod';
import type { PrecisionClock } from '@psyforge/timing';
import type { Scheduler, Timeline as SchedulerTimeline } from '@psyforge/scheduling';

export interface TimelineItem {
  id: string;
  execute(context: TimelineContext): Promise<void>;
  duration?: number;
  metadata?: Record<string, unknown>;
}

export interface TimelineContext {
  clock: PrecisionClock;
  scheduler: Scheduler;
  data: Record<string, unknown>;
  trial?: number;
  block?: number;
}

export interface TimelineOptions {
  repeat?: number;
  randomize?: boolean;
  conditions?: Record<string, unknown>[];
  metadata?: Record<string, unknown>;
}

export class Timeline implements TimelineItem {
  private items: TimelineItem[] = [];
  private options: TimelineOptions;
  public readonly id: string;

  constructor(id: string, options: TimelineOptions = {}) {
    this.id = id;
    this.options = options;
  }

  add(item: TimelineItem): this {
    this.items.push(item);
    return this;
  }

  repeat(times: number): this {
    this.options.repeat = times;
    return this;
  }

  randomize(): this {
    this.options.randomize = true;
    return this;
  }

  conditions(conditionList: Record<string, unknown>[]): this {
    this.options.conditions = conditionList;
    return this;
  }

  metadata(data: Record<string, unknown>): this {
    this.options.metadata = data;
    return this;
  }

  private shuffleItems(items: TimelineItem[]): TimelineItem[] {
    const shuffled = [...items];
    for (let i = shuffled.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
    }
    return shuffled;
  }

  private async executeItems(items: TimelineItem[], context: TimelineContext): Promise<void> {
    for (let i = 0; i < items.length; i++) {
      const item = items[i];

      // Update context for nested timelines
      const itemContext: TimelineContext = {
        ...context,
        trial: context.trial !== undefined ? context.trial + i : i,
      };

      await item.execute(itemContext);
    }
  }

  async execute(context: TimelineContext): Promise<void> {
    const repeatCount = this.options.repeat ?? 1;
    const conditions = this.options.conditions ?? [{}];

    for (let rep = 0; rep < repeatCount; rep++) {
      for (let condIndex = 0; condIndex < conditions.length; condIndex++) {
        const condition = conditions[condIndex];

        // Merge condition data into context
        const conditionContext: TimelineContext = {
          ...context,
          data: { ...context.data, ...condition },
          block: rep,
        };

        let itemsToExecute = [...this.items];

        // Randomize if requested
        if (this.options.randomize) {
          itemsToExecute = this.shuffleItems(itemsToExecute);
        }

        await this.executeItems(itemsToExecute, conditionContext);
      }
    }
  }

  getItems(): TimelineItem[] {
    return [...this.items];
  }

  getOptions(): TimelineOptions {
