import type { PrecisionClock } from '@psyforge/timing';
import type { DeviceManager } from '@psyforge/devices';
import type { Scheduler } from '@psyforge/scheduling';
import { BaseComponent, type ComponentContext } from './BaseComponent.js';

export interface SystemPerformanceMetrics {
  frameTime: number;
  avgFrameTime: number;
  maxFrameTime: number;
  frameCount: number;
  componentsCount: number;
  lastUpdate: number;
}

export interface ComponentSystemOptions {
  targetFrameTime?: number; // Default 16.67ms (60fps)
  maxFrameTime?: number;    // Default 2ms as per requirements
  enableMetrics?: boolean;
  enableHotReload?: boolean;
}

export class ComponentSystem {
  private root: BaseComponent;
  private context: ComponentContext;
  private isRunning = false;
  private animationFrameId?: number;
  private lastFrameTime = 0;
  private options: Required<ComponentSystemOptions>;
  private metrics: SystemPerformanceMetrics;
  private frameTimeHistory: number[] = [];
  private readonly MAX_HISTORY = 60; // Track last 60 frames

  constructor(
    clock: PrecisionClock,
    devices: DeviceManager,
    scheduler: Scheduler,
    container: HTMLElement,
    options: ComponentSystemOptions = {}
  ) {
    // Create root component
    this.root = new RootComponent('__root__');

    // Setup context
    this.context = {
      clock,
      devices,
      scheduler,
      container,
      data: {},
    };

    // Setup options with defaults
    this.options = {
      targetFrameTime: 16.67, // 60fps
      maxFrameTime: 2.0,      // 2ms maximum as per requirements
      enableMetrics: true,
      enableHotReload: false,
      ...options,
    };

    // Initialize metrics
    this.metrics = {
      frameTime: 0,
      avgFrameTime: 0,
      maxFrameTime: 0,
      frameCount: 0,
      componentsCount: 0,
      lastUpdate: 0,
    };

    this.setupEventListeners();
  }

  private setupEventListeners(): void {
    // Forward DOM events to component system
    const eventTypes = ['click', 'keydown', 'keyup', 'mousemove', 'mousedown', 'mouseup', 'touchstart', 'touchend'];

    for (const eventType of eventTypes) {
      this.context.container.addEventListener(eventType, (event) => {
        this.root.handleInput(event, this.context);
      });
    }

    // Handle resize
    window.addEventListener('resize', () => {
      this.updateCanvasSize();
    });
  }

  private updateCanvasSize(): void {
    if (this.context.canvas) {
      const rect = this.context.container.getBoundingClientRect();
      this.context.canvas.width = rect.width;
      this.context.canvas.height = rect.height;
    }
  }

  async add(component: BaseComponent): Promise<void> {
    this.root.addChild(component);
    if (this.isRunning) {
      await component.initialize(this.context);
    }
  }

  remove(component: BaseComponent): boolean {
    return this.root.removeChild(component);
  }

  findById(id: string): BaseComponent | undefined {
    return this.root.findChildById(id);
  }

  findByType(type: string): BaseComponent[] {
    return this.root.findChildrenByType(type);
  }

  findByTag(tag: string): BaseComponent[] {
    return this.root.findChildrenByTag(tag);
  }

  async start(): Promise<void> {
    if (this.isRunning) {
      return;
    }

    // Initialize all components
    await this.root.initialize(this.context);

    this.isRunning = true;
    this.lastFrameTime = this.context.clock.now();
    this.runLoop();
  }

  async stop(): Promise<void> {
    if (!this.isRunning) {
      return;
    }

    this.isRunning = false;
    if (this.animationFrameId) {
      cancelAnimationFrame(this.animationFrameId);
      this.animationFrameId = undefined;
    }

    await this.root.dispose(this.context);
  }

  private runLoop(): void {
    if (!this.isRunning) {
      return;
    }

    const frameStart = this.context.clock.now();
    const deltaTime = frameStart - this.lastFrameTime;

    // Update all components
    this.root.update(deltaTime, this.context);

    const frameEnd = this.context.clock.now();
    const frameTime = frameEnd - frameStart;

    // Update metrics
    this.updateMetrics(frameTime, deltaTime);

    // Performance monitoring
    if (this.options.enableMetrics && frameTime > this.options.maxFrameTime) {
      console.warn(`Frame time exceeded limit: ${frameTime.toFixed(2)}ms > ${this.options.maxFrameTime}ms`);
    }

    this.lastFrameTime = frameStart;
    this.animationFrameId = requestAnimationFrame(() => this.runLoop());
  }

  private updateMetrics(frameTime: number, deltaTime: number): void {
    this.metrics.frameTime = frameTime;
    this.metrics.frameCount++;
    this.metrics.lastUpdate = this.context.clock.now();
    this.metrics.componentsCount = this.countComponents(this.root);

    // Track frame time history
    this.frameTimeHistory.push(frameTime);
    if (this.frameTimeHistory.length > this.MAX_HISTORY) {
      this.frameTimeHistory.shift();
    }

    // Calculate averages
    this.metrics.avgFrameTime = this.frameTimeHistory.reduce((a, b) => a + b, 0) / this.frameTimeHistory.length;
    this.metrics.maxFrameTime = Math.max(...this.frameTimeHistory);
  }

  private countComponents(component: BaseComponent): number {
    let count = 1;
    for (const child of component.getChildren()) {
      count += this.countComponents(child);
    }
    return count;
  }

  getMetrics(): Readonly<SystemPerformanceMetrics> {
    return { ...this.metrics };
  }

  // Hot reload support for development
  async reloadComponent(id: string, newComponent: BaseComponent): Promise<boolean> {
    if (!this.options.enableHotReload) {
      return false;
    }

    const oldComponent = this.findById(id);
    if (!oldComponent || !oldComponent.parent) {
      return false;
    }

    const parent = oldComponent.parent;
    await oldComponent.dispose(this.context);
    parent.removeChild(oldComponent);
    parent.addChild(newComponent);

    if (this.isRunning) {
      await newComponent.initialize(this.context);
    }

    return true;
  }

  // Context management
  setData(key: string, value: unknown): void {
    this.context.data[key] = value;
  }

  getData<T>(key: string): T | undefined {
    return this.context.data[key] as T;
  }

  setTrial(trial: number): void {
    this.context.trial = trial;
  }

  setBlock(block: number): void {
    this.context.block = block;
  }

  // Canvas management for high-performance rendering
  createCanvas(): HTMLCanvasElement {
    const canvas = document.createElement('canvas');
    canvas.style.position = 'absolute';
    canvas.style.top = '0';
    canvas.style.left = '0';
    canvas.style.pointerEvents = 'none';

    this.context.container.appendChild(canvas);
    this.context.canvas = canvas;
    this.updateCanvasSize();

    return canvas;
  }

  getCanvas(): HTMLCanvasElement | undefined {
    return this.context.canvas;
  }

  // Performance analysis
  getPerformanceReport(): {
    isHealthy: boolean;
    issues: string[];
    recommendations: string[];
    metrics: SystemPerformanceMetrics;
  } {
    const issues: string[] = [];
    const recommendations: string[] = [];

    if (this.metrics.maxFrameTime > this.options.maxFrameTime) {
      issues.push(`Max frame time (${this.metrics.maxFrameTime.toFixed(2)}ms) exceeds limit (${this.options.maxFrameTime}ms)`);
      recommendations.push('Consider optimizing component update logic or reducing component count');
    }

    if (this.metrics.avgFrameTime > this.options.targetFrameTime) {
      issues.push(`Average frame time (${this.metrics.avgFrameTime.toFixed(2)}ms) exceeds target (${this.options.targetFrameTime}ms)`);
      recommendations.push('Profile component performance and optimize heavy operations');
    }

    if (this.metrics.componentsCount > 1000) {
      recommendations.push('Consider component pooling or culling for large numbers of components');
    }

    return {
      isHealthy: issues.length === 0,
      issues,
      recommendations,
      metrics: this.getMetrics(),
    };
  }
}

// Root component for the system
class RootComponent extends BaseComponent {
  constructor(id: string) {
    super(id, 'Root');
  }

  async onInit(): Promise<void> {
    // Root component initialization
  }

  onFrame(): void {
    // Root component frame update
  }

  async onDispose(): Promise<void> {
    // Root component cleanup
  }
}

