import { BaseComponent, type ComponentContext } from '../BaseComponent.js';

export interface KeyboardResponse {
  key: string;
  code: string;
  timestamp: number;
  reactionTime: number;
  correct?: boolean;
}

export interface KeyboardComponentOptions {
  allowedKeys?: string[];          // Specific keys to listen for (e.g., ['ArrowLeft', 'ArrowRight'])
  allowedCodes?: string[];         // Specific key codes (e.g., ['KeyA', 'KeyL'])
  timeout?: number;                // Maximum time to wait for response
  firstKeyOnly?: boolean;          // Only capture first key press
  correctKeys?: string[];          // Keys that are considered correct responses
  preventDefault?: boolean;        // Prevent default browser behavior
  caseSensitive?: boolean;         // Whether key matching is case sensitive
  autoRelease?: boolean;           // Auto-release after response
}

export type KeyboardEventHandler = (response: KeyboardResponse, component: KeyboardComponent) => void | Promise<void>;

export class KeyboardComponent extends BaseComponent {
  private options: KeyboardComponentOptions;
  private onResponseHandler?: KeyboardEventHandler;
  private startTime = 0;
  private isListening = false;
  private hasResponded = false;
  private timeoutTimer?: number;
  private boundKeyHandler?: (event: KeyboardEvent) => void;

  constructor(id: string, options: KeyboardComponentOptions = {}) {
    super(id, 'Keyboard');
    this.options = {
      firstKeyOnly: true,
      preventDefault: true,
      caseSensitive: false,
      autoRelease: true,
      ...options,
    };
  }

  // Fluent API methods
  allowKeys(...keys: string[]): this {
    this.options.allowedKeys = keys;
    return this;
  }

  allowCodes(...codes: string[]): this {
    this.options.allowedCodes = codes;
    return this;
  }

  timeout(ms: number): this {
    this.options.timeout = ms;
    return this;
  }

  firstKeyOnly(value = true): this {
    this.options.firstKeyOnly = value;
    return this;
  }

  correctKeys(...keys: string[]): this {
    this.options.correctKeys = keys;
    return this;
  }

  preventDefault(value = true): this {
    this.options.preventDefault = value;
    return this;
  }

  caseSensitive(value = true): this {
    this.options.caseSensitive = value;
    return this;
  }

  autoRelease(value = true): this {
    this.options.autoRelease = value;
    return this;
  }

  onResponse(handler: KeyboardEventHandler): this {
    this.onResponseHandler = handler;
    return this;
  }

  async onInit(context: ComponentContext): Promise<void> {
    this.boundKeyHandler = this.handleKeydown.bind(this);
    this.startListening(context);
  }

  onFrame(deltaTime: number, context: ComponentContext): void {
    // Check timeout
    if (this.isListening && this.options.timeout && this.startTime > 0) {
      const elapsed = context.clock.now() - this.startTime;
      if (elapsed >= this.options.timeout) {
        this.handleTimeout(context);
      }
    }
  }

  async onDispose(context: ComponentContext): Promise<void> {
    this.stopListening();
  }

  onInput(event: Event, context: ComponentContext): boolean {
    if (event.type === 'keydown' && this.isListening && !this.hasResponded) {
      return this.handleKeydown(event as KeyboardEvent, context);
    }
    return false;
  }

  private handleKeydown(event: KeyboardEvent, context?: ComponentContext): boolean {
    if (!this.isListening || (this.options.firstKeyOnly && this.hasResponded)) {
      return false;
    }

    const key = this.options.caseSensitive ? event.key : event.key.toLowerCase();
    const code = event.code;

    // Check if key is allowed
    if (this.options.allowedKeys && !this.isKeyAllowed(key, this.options.allowedKeys)) {
      return false;
    }

    if (this.options.allowedCodes && !this.options.allowedCodes.includes(code)) {
      return false;
    }

    // Prevent default if requested
    if (this.options.preventDefault) {
      event.preventDefault();
      event.stopPropagation();
    }

    // Record response
    const timestamp = context?.clock.now() ?? performance.now();
    const reactionTime = this.startTime > 0 ? timestamp - this.startTime : 0;

    const response: KeyboardResponse = {
      key,
      code,
      timestamp,
      reactionTime,
      correct: this.isCorrectKey(key),
    };

    this.hasResponded = true;

    // Clear timeout
    if (this.timeoutTimer) {
      clearTimeout(this.timeoutTimer);
      this.timeoutTimer = undefined;
    }

    // Call response handler
    if (this.onResponseHandler) {
      try {
        const result = this.onResponseHandler(response, this);
        if (result instanceof Promise) {
          result.catch(error => console.error('Error in keyboard response handler:', error));
        }
      } catch (error) {
        console.error('Error in keyboard response handler:', error);
      }
    }

    // Auto-release if configured
    if (this.options.autoRelease) {
      this.stopListening();
    }

    return true;
  }

  private isKeyAllowed(key: string, allowedKeys: string[]): boolean {
    if (this.options.caseSensitive) {
      return allowedKeys.includes(key);
    }
    return allowedKeys.some(allowedKey => allowedKey.toLowerCase() === key.toLowerCase());
  }

  private isCorrectKey(key: string): boolean | undefined {
    if (!this.options.correctKeys) {
      return undefined;
    }

    if (this.options.caseSensitive) {
      return this.options.correctKeys.includes(key);
    }

    return this.options.correctKeys.some(correctKey => 
      correctKey.toLowerCase() === key.toLowerCase()
    );
  }

  private handleTimeout(context: ComponentContext): void {
    if (!this.isListening) {
      return;
    }

    const timestamp = context.clock.now();
    const response: KeyboardResponse = {
      key: '',
      code: '',
      timestamp,
      reactionTime: this.options.timeout || 0,
      correct: false,
    };

    this.hasResponded = true;
    this.stopListening();

    // Call response handler for timeout
    if (this.onResponseHandler) {
      try {
        const result = this.onResponseHandler(response, this);
        if (result instanceof Promise) {
          result.catch(error => console.error('Error in keyboard timeout handler:', error));
        }
      } catch (error) {
        console.error('Error in keyboard timeout handler:', error);
      }
    }
  }

  // Public control methods
  startListening(context: ComponentContext): void {
    if (this.isListening) {
      return;
    }

    this.isListening = true;
    this.hasResponded = false;
    this.startTime = context.clock.now();

    // Add global event listener
    if (this.boundKeyHandler) {
      document.addEventListener('keydown', this.boundKeyHandler, true);
    }

    // Setup timeout
    if (this.options.timeout) {
      this.timeoutTimer = window.setTimeout(() => {
        this.handleTimeout(context);
      }, this.options.timeout);
    }
  }

  stopListening(): void {
    if (!this.isListening) {
      return;
    }

    this.isListening = false;

    // Remove global event listener
    if (this.boundKeyHandler) {
      document.removeEventListener('keydown', this.boundKeyHandler, true);
    }

    // Clear timeout
    if (this.timeoutTimer) {
      clearTimeout(this.timeoutTimer);
      this.timeoutTimer = undefined;
    }
  }

  reset(): void {
    this.stopListening();
    this.hasResponded = false;
    this.startTime = 0;
  }

  // State getters
  get listening(): boolean {
    return this.isListening;
  }

  get responded(): boolean {
    return this.hasResponded;
  }

  get elapsedTime(): number {
    if (this.startTime === 0) {
      return 0;
    }
    return performance.now() - this.startTime;
  }

  // Convenience methods for common use cases
  static waitForAnyKey(id = 'keyboard-any', timeout?: number): KeyboardComponent {
    return new KeyboardComponent(id, { timeout });
  }

  static waitForKeys(keys: string[], id = 'keyboard-specific', timeout?: number): KeyboardComponent {
    return new KeyboardComponent(id, { allowedKeys: keys, timeout });
  }

  static waitForSpacebar(id = 'keyboard-space', timeout?: number): KeyboardComponent {
    return new KeyboardComponent(id, { allowedKeys: [' ', 'Space'], timeout });
  }

  static waitForArrowKeys(id = 'keyboard-arrows', timeout?: number): KeyboardComponent {
    return new KeyboardComponent(id, { 
      allowedKeys: ['ArrowLeft', 'ArrowRight', 'ArrowUp', 'ArrowDown'], 
      timeout 
    });
  }

  static yesNoResponse(id = 'keyboard-yesno', yesKey = 'y', noKey = 'n', timeout?: number): KeyboardComponent {
    return new KeyboardComponent(id, { 
      allowedKeys: [yesKey, noKey], 
      caseSensitive: false,
      timeout 
    });
  }

  // Override serialize to include component-specific data
  serialize(): Record<string, unknown> {
    return {
      ...super.serialize(),
      options: this.options,
      isListening: this.isListening,
      hasResponded: this.hasResponded,
      startTime: this.startTime,
    };
  }
}

