import { BaseComponent, type ComponentContext } from '../BaseComponent.js';

export type LayoutType = 'stack' | 'grid' | 'flex' | 'absolute' | 'center' | 'circle';

export interface Alignment {
  horizontal: 'left' | 'center' | 'right' | 'stretch';
  vertical: 'top' | 'center' | 'bottom' | 'stretch';
}

export interface Spacing {
  x: number;
  y: number;
}

export interface GridLayoutOptions {
  columns: number;
  rows?: number;
  spacing?: Spacing;
  alignment?: Alignment;
  padding?: Spacing;
}

export interface StackLayoutOptions {
  direction: 'horizontal' | 'vertical';
  spacing?: number;
  alignment?: Alignment;
  padding?: Spacing;
}

export interface FlexLayoutOptions {
  direction: 'row' | 'column' | 'row-reverse' | 'column-reverse';
  wrap?: boolean;
  justifyContent?: 'flex-start' | 'flex-end' | 'center' | 'space-between' | 'space-around' | 'space-evenly';
  alignItems?: 'flex-start' | 'flex-end' | 'center' | 'stretch' | 'baseline';
  gap?: Spacing;
  padding?: Spacing;
}

export interface CircleLayoutOptions {
  radius: number;
  startAngle?: number; // in degrees
  spacing?: number;    // angle between items in degrees
  center?: { x: number; y: number };
}

export interface AbsoluteLayoutOptions {
  positions: Array<{ x: number; y: number }>;
}

export interface CenterLayoutOptions {
  offset?: { x: number; y: number };
}

export type LayoutOptions = 
  | { type: 'grid'; options: GridLayoutOptions }
  | { type: 'stack'; options: StackLayoutOptions }
  | { type: 'flex'; options: FlexLayoutOptions }
  | { type: 'circle'; options: CircleLayoutOptions }
  | { type: 'absolute'; options: AbsoluteLayoutOptions }
  | { type: 'center'; options?: CenterLayoutOptions };

export class LayoutComponent extends BaseComponent {
  private layoutConfig: LayoutOptions;
  private containerElement?: HTMLElement;
  private lastChildCount = 0;

  constructor(id: string, layoutConfig: LayoutOptions) {
    super(id, 'Layout');
    this.layoutConfig = layoutConfig;
  }

  // Fluent API for creating different layout types
  static grid(id: string, columns: number, rows?: number): LayoutComponent {
    return new LayoutComponent(id, { 
      type: 'grid', 
      options: { columns, rows } 
    });
  }

  static stack(id: string, direction: 'horizontal' | 'vertical' = 'vertical'): LayoutComponent {
    return new LayoutComponent(id, { 
      type: 'stack', 
      options: { direction } 
    });
  }

  static flex(id: string, direction: 'row' | 'column' = 'row'): LayoutComponent {
    return new LayoutComponent(id, { 
      type: 'flex', 
      options: { direction } 
    });
  }

  static circle(id: string, radius: number): LayoutComponent {
    return new LayoutComponent(id, { 
      type: 'circle', 
      options: { radius } 
    });
  }

  static absolute(id: string, positions: Array<{ x: number; y: number }>): LayoutComponent {
    return new LayoutComponent(id, { 
      type: 'absolute', 
      options: { positions } 
    });
  }

  static center(id: string): LayoutComponent {
    return new LayoutComponent(id, { 
      type: 'center' 
    });
  }

  // Configuration methods
  spacing(x: number, y?: number): this {
    const spacing = { x, y: y ?? x };

    if (this.layoutConfig.type === 'grid') {
      this.layoutConfig.options.spacing = spacing;
    } else if (this.layoutConfig.type === 'stack') {
      this.layoutConfig.options.spacing = x;
    } else if (this.layoutConfig.type === 'flex') {
      this.layoutConfig.options.gap = spacing;
    }

    return this;
  }

  alignment(horizontal: 'left' | 'center' | 'right' | 'stretch', 
           vertical: 'top' | 'center' | 'bottom' | 'stretch'): this {
    const alignment = { horizontal, vertical };

    if (this.layoutConfig.type === 'grid' || this.layoutConfig.type === 'stack') {
      this.layoutConfig.options.alignment = alignment;
    }

    return this;
  }

  padding(x: number, y?: number): this {
    const padding = { x, y: y ?? x };

    if (this.layoutConfig.type === 'grid' || 
        this.layoutConfig.type === 'stack' || 
        this.layoutConfig.type === 'flex') {
      this.layoutConfig.options.padding = padding;
    }

    return this;
  }

  async onInit(context: ComponentContext): Promise<void> {
    this.containerElement = this.createContainer(context);
    context.container.appendChild(this.containerElement);
    this.applyLayout();
  }

  onFrame(deltaTime: number, context: ComponentContext): void {
    // Check if children have changed and re-layout if necessary
    if (this.children.length !== this.lastChildCount) {
      this.applyLayout();
      this.lastChildCount = this.children.length;
    }

    // Update container transform
    this.updateContainerTransform();
  }

  async onDispose(context: ComponentContext): Promise<void> {
    if (this.containerElement && this.containerElement.parentNode) {
      this.containerElement.parentNode.removeChild(this.containerElement);
      this.containerElement = undefined;
    }
  }

  private createContainer(context: ComponentContext): HTMLElement {
    const container = document.createElement('div');
    container.style.position = 'absolute';
    container.style.pointerEvents = 'none';

    // Apply flex layout to container for flex type
    if (this.layoutConfig.type === 'flex') {
      const options = this.layoutConfig.options;
      container.style.display = 'flex';
      container.style.flexDirection = options.direction;
      container.style.flexWrap = options.wrap ? 'wrap' : 'nowrap';
      container.style.justifyContent = options.justifyContent || 'flex-start';
      container.style.alignItems = options.alignItems || 'stretch';

      if (options.gap) {
        container.style.gap = `${options.gap.y}px ${options.gap.x}px`;
      }

      if (options.padding) {
        container.style.padding = `${options.padding.y}px ${options.padding.x}px`;
      }
    }

    return container;
  }

  private updateContainerTransform(): void {
    if (!this.containerElement) return;

    const pos = this.worldPosition;
    this.containerElement.style.left = `${pos.x}px`;
    this.containerElement.style.top = `${pos.y}px`;
    this.containerElement.style.transform = `rotate(${this.transform.rotation}deg) scale(${this.transform.scale.x}, ${this.transform.scale.y})`;
    this.containerElement.style.opacity = this.worldOpacity.toString();
    this.containerElement.style.display = this.transform.visible ? 'block' : 'none';

    if (this.transform.position.z !== undefined) {
      this.containerElement.style.zIndex = this.transform.position.z.toString();
    }
  }

  private applyLayout(): void {
    switch (this.layoutConfig.type) {
      case 'grid':
        this.applyGridLayout();
        break;
      case 'stack':
        this.applyStackLayout();
        break;
      case 'flex':
        this.applyFlexLayout();
        break;
      case 'circle':
        this.applyCircleLayout();
        break;
      case 'absolute':
        this.applyAbsoluteLayout();
        break;
      case 'center':
        this.applyCenterLayout();
        break;
    }
  }

  private applyGridLayout(): void {
    if (this.layoutConfig.type !== 'grid') return;

    const options = this.layoutConfig.options;
    const children = this.getChildren();
    const columns = options.columns;
    const rows = options.rows || Math.ceil(children.length / columns);
    const spacing = options.spacing || { x: 0, y: 0 };

    children.forEach((child, index) => {
      const row = Math.floor(index / columns);
      const col = index % columns;

      const x = col * spacing.x;
      const y = row * spacing.y;

      child.position(x, y);
    });
  }

  private applyStackLayout(): void {
    if (this.layoutConfig.type !== 'stack') return;

    const options = this.layoutConfig.options;
    const children = this.getChildren();
    const spacing = options.spacing || 0;

    children.forEach((child, index) => {
      if (options.direction === 'horizontal') {
        child.position(index * spacing, 0);
      } else {
        child.position(0, index * spacing);
      }
    });
  }

  private applyFlexLayout(): void {
    // Flex layout is handled by CSS in the container
    // Child positioning is managed by the browser's flex layout
  }

  private applyCircleLayout(): void {
    if (this.layoutConfig.type !== 'circle') return;

    const options = this.layoutConfig.options;
    const children = this.getChildren();
    const radius = options.radius;
    const startAngle = (options.startAngle || 0) * Math.PI / 180;
    const spacing = options.spacing ? options.spacing * Math.PI / 180 : (2 * Math.PI) / children.length;
    const center = options.center || { x: 0, y: 0 };

    children.forEach((child, index) => {
      const angle = startAngle + index * spacing;
      const x = center.x + radius * Math.cos(angle);
      const y = center.y + radius * Math.sin(angle);

      child.position(x, y);
    });
  }

  private applyAbsoluteLayout(): void {
    if (this.layoutConfig.type !== 'absolute') return;

    const options = this.layoutConfig.options;
    const children = this.getChildren();

    children.forEach((child, index) => {
      if (index < options.positions.length) {
        const pos = options.positions[index];
        child.position(pos.x, pos.y);
      }
    });
  }

  private applyCenterLayout(): void {
    if (this.layoutConfig.type !== 'center') return;

    const options = this.layoutConfig.options;
    const children = this.getChildren();
    const offset = options?.offset || { x: 0, y: 0 };

    children.forEach(child => {
      child.position(offset.x, offset.y);
    });
  }

  // Method to change layout type at runtime
  changeLayout(newLayout: LayoutOptions): void {
    this.layoutConfig = newLayout;

    // Update container for flex layout
    if (this.containerElement && newLayout.type === 'flex') {
      const options = newLayout.options;
      this.containerElement.style.display = 'flex';
      this.containerElement.style.flexDirection = options.direction;
      this.containerElement.style.flexWrap = options.wrap ? 'wrap' : 'nowrap';
      this.containerElement.style.justifyContent = options.justifyContent || 'flex-start';
      this.containerElement.style.alignItems = options.alignItems || 'stretch';
    } else if (this.containerElement) {
      this.containerElement.style.display = 'block';
    }

    this.applyLayout();
  }

  // Get layout information
  getLayoutInfo(): {
    type: LayoutType;
    childPositions: Array<{ id: string; x: number; y: number }>;
    bounds: { width: number; height: number };
  } {
    const children = this.getChildren();
    const childPositions = children.map(child => ({
      id: child.id,
      x: child.worldPosition.x,
      y: child.worldPosition.y,
    }));

    // Calculate bounds
    let minX = 0, minY = 0, maxX = 0, maxY = 0;
    if (childPositions.length > 0) {
      minX = Math.min(...childPositions.map(p => p.x));
      minY = Math.min(...childPositions.map(p => p.y));
      maxX = Math.max(...childPositions.map(p => p.x));
      maxY = Math.max(...childPositions.map(p => p.y));
    }

    return {
      type: this.layoutConfig.type,
      childPositions,
      bounds: {
        width: maxX - minX,
        height: maxY - minY,
      },
    };
  }

  // Override serialize to include layout configuration
  serialize(): Record<string, unknown> {
    return {
      ...super.serialize(),
      layoutConfig: this.layoutConfig,
    };
  }
}

