import type { PrecisionClock } from '@psyforge/timing';
import type { DeviceManager } from '@psyforge/devices';
import type { Scheduler } from '@psyforge/scheduling';

import { ComponentSystem } from './components/ComponentSystem.js';
import { TextComponent, type TextComponentOptions } from './components/display/TextComponent.js';
import { KeyboardComponent, type KeyboardComponentOptions } from './components/input/KeyboardComponent.js';
import { LayoutComponent, type LayoutOptions } from './components/layout/LayoutComponent.js';
import { BaseComponent } from './components/BaseComponent.js';

export interface ForgeBuilderOptions {
  container: HTMLElement;
  clock: PrecisionClock;
  devices: DeviceManager;
  scheduler: Scheduler;
  enableMetrics?: boolean;
  enableHotReload?: boolean;
  maxFrameTime?: number;
}

export interface TrialBuilder {
  duration(ms: number): TrialBuilder;
  onComplete(handler: () => void | Promise<void>): TrialBuilder;
  build(): Trial;
}

export class Trial {
  private components: BaseComponent[] = [];
  private durationMs?: number;
  private onCompleteHandler?: () => void | Promise<void>;

  constructor() {}

  addComponent(component: BaseComponent): this {
    this.components.push(component);
    return this;
  }

  setDuration(ms: number): this {
    this.durationMs = ms;
    return this;
  }

  setOnComplete(handler: () => void | Promise<void>): this {
    this.onCompleteHandler = handler;
    return this;
  }

  getComponents(): ReadonlyArray<BaseComponent> {
    return this.components;
  }

  getDuration(): number | undefined {
    return this.durationMs;
  }

  async execute(system: ComponentSystem): Promise<void> {
    // Add all components to the system
    for (const component of this.components) {
      await system.add(component);
    }

    // Wait for trial duration or completion
    if (this.durationMs) {
      await new Promise(resolve => setTimeout(resolve, this.durationMs!));
    }

    // Call completion handler
    if (this.onCompleteHandler) {
      await this.onCompleteHandler();
    }

    // Remove components
    for (const component of this.components) {
      system.remove(component);
    }
  }
}

export class ForgeBuilder {
  private system: ComponentSystem;
  private componentIdCounter = 0;

  constructor(options: ForgeBuilderOptions) {
    this.system = new ComponentSystem(
      options.clock,
      options.devices,
      options.scheduler,
      options.container,
      {
        enableMetrics: options.enableMetrics,
        enableHotReload: options.enableHotReload,
        maxFrameTime: options.maxFrameTime,
      }
    );
  }

  // Core system methods
  async start(): Promise<void> {
    await this.system.start();
  }

  async stop(): Promise<void> {
    await this.system.stop();
  }

  getSystem(): ComponentSystem {
    return this.system;
  }

  getMetrics() {
    return this.system.getMetrics();
  }

  getPerformanceReport() {
    return this.system.getPerformanceReport();
  }

  // Fluent API for creating components
  text(content: string | ((context: any) => string), options: Partial<TextComponentOptions> = {}): TextComponent {
    const id = `text_${this.componentIdCounter++}`;
    return new TextComponent(id, { text: content, ...options });
  }

  keyboard(options: KeyboardComponentOptions = {}): KeyboardComponent {
    const id = `keyboard_${this.componentIdCounter++}`;
    return new KeyboardComponent(id, options);
  }

  layout(layoutConfig: LayoutOptions): LayoutComponent {
    const id = `layout_${this.componentIdCounter++}`;
    return new LayoutComponent(id, layoutConfig);
  }

  // Convenience methods for common patterns
  fixation(symbol = '+', duration = 1000): TextComponent {
    return this.text(symbol)
      .fontSize(48)
      .textAlign('center')
      .duration(duration)
      .tag('fixation');
  }

  instruction(text: string, continueKey = ' '): [TextComponent, KeyboardComponent] {
    const textComp = this.text(text)
      .fontSize(24)
      .textAlign('center')
      .position(0, -50)
      .tag('instruction');

    const keyComp = this.keyboard({ allowedKeys: [continueKey] })
      .tag('instruction-input');

    return [textComp, keyComp];
  }

  feedback(text: string, duration = 1000, color = 'green'): TextComponent {
    return this.text(text)
      .fontSize(32)
      .color(color)
      .textAlign('center')
      .duration(duration)
      .fadeIn(200)
      .fadeOut(200)
      .tag('feedback');
  }

  choiceTask(stimulus: string, leftKey = 'f', rightKey = 'j', timeout?: number): [TextComponent, KeyboardComponent] {
    const stimComp = this.text(stimulus)
      .fontSize(36)
      .textAlign('center')
      .tag('stimulus');

    const respComp = this.keyboard({ 
      allowedKeys: [leftKey, rightKey], 
      timeout 
    }).tag('response');

    return [stimComp, respComp];
  }

  stroop(word: string, color: string, responseKeys = ['f', 'j']): [TextComponent, KeyboardComponent] {
    const congruent = word.toLowerCase() === color.toLowerCase();

    const textComp = this.text(word)
      .fontSize(48)
      .color(color)
      .textAlign('center')
      .setUserData('congruent', congruent)
      .setUserData('word', word)
      .setUserData('color', color)
      .tag('stroop-stimulus');

    const keyComp = this.keyboard({ allowedKeys: responseKeys })
      .tag('stroop-response');

    return [textComp, keyComp];
  }

  // Layout helpers
  centerLayout(): LayoutComponent {
    return this.layout({ type: 'center' });
  }

  gridLayout(columns: number, rows?: number): LayoutComponent {
    return this.layout({ type: 'grid', options: { columns, rows } });
  }

  stackLayout(direction: 'horizontal' | 'vertical' = 'vertical'): LayoutComponent {
    return this.layout({ type: 'stack', options: { direction } });
  }

  circleLayout(radius: number): LayoutComponent {
    return this.layout({ type: 'circle', options: { radius } });
  }

  // Trial building
  trial(): TrialBuilderImpl {
    return new TrialBuilderImpl(this);
  }

  // Advanced component creation
  component<T extends BaseComponent>(
    componentClass: new (id: string, ...args: any[]) => T,
    ...args: any[]
  ): T {
    const id = `component_${this.componentIdCounter++}`;
    return new componentClass(id, ...args);
  }

  // Experiment running
  async runTrial(trial: Trial): Promise<void> {
