  }

  async onDispose(context: ComponentContext): Promise<void> {
    this.stop();
  }

  private applyKeyframes(progress: number): void {
    if (!this.target || !this.options.keyframes) {
      return;
    }

    // Find surrounding keyframes
    const keyframes = this.options.keyframes.sort((a, b) => a.time - b.time);
    let startKeyframe = keyframes[0];
    let endKeyframe = keyframes[keyframes.length - 1];

    for (let i = 0; i < keyframes.length - 1; i++) {
      if (progress >= keyframes[i].time && progress <= keyframes[i + 1].time) {
        startKeyframe = keyframes[i];
        endKeyframe = keyframes[i + 1];
        break;
      }
    }

    // Calculate local progress between keyframes
    const keyframeDuration = endKeyframe.time - startKeyframe.time;
    const localProgress = keyframeDuration > 0 
      ? (progress - startKeyframe.time) / keyframeDuration 
      : 1;

    // Apply easing
    const easing = endKeyframe.easing || 'linear';
    const easedProgress = this.applyEasing(localProgress, easing);

    // Interpolate values
    this.interpolateTransform(startKeyframe, endKeyframe, easedProgress);
  }

  private interpolateTransform(start: AnimationKeyframe, end: AnimationKeyframe, progress: number): void {
    if (!this.target) return;

    const targetTransform = (this.target as any).transform;

    // Position interpolation
    if (end.position) {
      const startPos = start.position || this.initialTransform.position;
      const endPos = end.position;

      const x = this.lerp(startPos.x, endPos.x, progress);
      const y = this.lerp(startPos.y, endPos.y, progress);
      const z = endPos.z !== undefined ? this.lerp(startPos.z || 0, endPos.z, progress) : undefined;

      this.target.position(x, y, z);
    }

    // Rotation interpolation
    if (end.rotation !== undefined) {
      const startRot = start.rotation !== undefined ? start.rotation : this.initialTransform.rotation;
      const endRot = end.rotation;

      const rotation = this.lerp(startRot, endRot, progress);
      this.target.rotate(rotation);
    }

    // Scale interpolation
    if (end.scale) {
      const startScale = start.scale || this.initialTransform.scale;
      const endScale = end.scale;

      const scaleX = this.lerp(startScale.x, endScale.x, progress);
      const scaleY = this.lerp(startScale.y, endScale.y, progress);

      this.target.scale(scaleX, scaleY);
    }

    // Opacity interpolation
    if (end.opacity !== undefined) {
      const startOpacity = start.opacity !== undefined ? start.opacity : this.initialTransform.opacity;
      const endOpacity = end.opacity;

      const opacity = this.lerp(startOpacity, endOpacity, progress);
      this.target.opacity(opacity);
    }
  }

  private lerp(start: number, end: number, t: number): number {
    return start + (end - start) * t;
  }

  private applyEasing(t: number, easing: EasingFunction): number {
    if (typeof easing === 'function') {
      return easing(t);
    }

    switch (easing) {
      case 'linear':
        return t;
      case 'easeIn':
        return t * t;
      case 'easeOut':
        return 1 - (1 - t) * (1 - t);
      case 'easeInOut':
        return t < 0.5 ? 2 * t * t : 1 - 2 * (1 - t) * (1 - t);
      case 'bounceIn':
        return 1 - this.bounceOut(1 - t);
      case 'bounceOut':
        return this.bounceOut(t);
      case 'bounceInOut':
        return t < 0.5 
          ? (1 - this.bounceOut(1 - 2 * t)) / 2
          : (1 + this.bounceOut(2 * t - 1)) / 2;
      case 'elasticIn':
        return this.elasticIn(t);
      case 'elasticOut':
        return this.elasticOut(t);
      case 'elasticInOut':
        return t < 0.5 
          ? this.elasticIn(2 * t) / 2
          : (2 - this.elasticIn(2 * (1 - t))) / 2;
      default:
        return t;
    }
  }

  private bounceOut(t: number): number {
    if (t < 1 / 2.75) {
      return 7.5625 * t * t;
    } else if (t < 2 / 2.75) {
      return 7.5625 * (t -= 1.5 / 2.75) * t + 0.75;
    } else if (t < 2.5 / 2.75) {
      return 7.5625 * (t -= 2.25 / 2.75) * t + 0.9375;
    } else {
      return 7.5625 * (t -= 2.625 / 2.75) * t + 0.984375;
    }
  }

  private elasticIn(t: number): number {
    if (t === 0) return 0;
    if (t === 1) return 1;
    return -Math.pow(2, 10 * (t - 1)) * Math.sin((t - 1.1) * 5 * Math.PI);
  }

  private elasticOut(t: number): number {
    if (t === 0) return 0;
    if (t === 1) return 1;
    return Math.pow(2, -10 * t) * Math.sin((t - 0.1) * 5 * Math.PI) + 1;
  }

  private handleCompletion(): void {
    if (this.options.loop) {
      this.currentIteration++;

      // Check if we should continue looping
      const shouldContinue = this.options.loop === true || 
        (typeof this.options.loop === 'number' && this.currentIteration < this.options.loop);

      if (shouldContinue) {
        // Call loop handler
        if (this.options.onLoop) {
          try {
            const result = this.options.onLoop(this.currentIteration);
            if (result instanceof Promise) {
              result.catch(error => console.error('Error in animation loop handler:', error));
            }
          } catch (error) {
            console.error('Error in animation loop handler:', error);
          }
        }

        // Restart animation
        this.startTime = performance.now();
        return;
      }
    }

    // Animation completed
    this.isPlaying = false;

    // Call completion handler
    if (this.options.onComplete) {
      try {
        const result = this.options.onComplete();
        if (result instanceof Promise) {
          result.catch(error => console.error('Error in animation completion handler:', error));
        }
      } catch (error) {
        console.error('Error in animation completion handler:', error);
      }
    }
  }

  // Public control methods
  play(context: ComponentContext): void {
    if (this.isPlaying && !this.isPaused) {
      return;
    }

    this.isPlaying = true;
    this.isPaused = false;
    this.startTime = context.clock.now();
  }

  pause(): void {
    this.isPaused = true;
  }

  resume(context: ComponentContext): void {
    if (!this.isPaused) {
      return;
    }

    this.isPaused = false;
    // Adjust start time to account for pause duration
    const pauseDuration = context.clock.now() - this.startTime;
    this.startTime = context.clock.now() - pauseDuration;
  }

  stop(): void {
    this.isPlaying = false;
    this.isPaused = false;
    this.currentIteration = 0;
  }

  reset(): void {
    this.stop();
    if (this.target && this.initialTransform) {
      this.target.position(this.initialTransform.position.x, this.initialTransform.position.y, this.initialTransform.position.z);
      this.target.rotate(this.initialTransform.rotation);
      this.target.scale(this.initialTransform.scale.x, this.initialTransform.scale.y);
      this.target.opacity(this.initialTransform.opacity);
    }
  }

  // State getters
  get playing(): boolean {
    return this.isPlaying;
  }

  get paused(): boolean {
    return this.isPaused;
  }

  get iteration(): number {
    return this.currentIteration;
  }

  // Override serialize to include animation data
  serialize(): Record<string, unknown> {
    return {
      ...super.serialize(),
      options: this.options,
      isPlaying: this.isPlaying,
      isPaused: this.isPaused,
      currentIteration: this.currentIteration,
    };
  }
}

