**Onboarding Implementation:**
```typescript
// @psyforge/onboarding
export class FirstRunOrbit {
  private steps: OnboardingStep[];
  private currentStep: number = 0;
  private userProgress: UserProgress;

  constructor() {
    this.steps = this.defineOnboardingSteps();
    this.userProgress = new UserProgress();
  }

  private defineOnboardingSteps(): OnboardingStep[] {
    return [
      {
        id: 'welcome',
        title: 'Welcome to Psycho-Forge',
        description: 'Let\'s explore the Scientific Operating System for Behavioral Research',
        component: WelcomeStep,
        estimatedDuration: 30, // seconds
        required: true
      },

      {
        id: 'create_experiment',
        title: 'Create Your First Experiment',
        description: 'Learn how to design experiments with ForgeScript',
        component: CreateExperimentStep,
        estimatedDuration: 180,
        required: true,
        prerequisites: ['welcome']
      },

      {
        id: 'visual_design',
        title: 'Visual Timeline Design',
        description: 'Explore the Mirror-Canvas for visual experiment design',
        component: VisualDesignStep,
        estimatedDuration: 120,
        required: true,
        prerequisites: ['create_experiment']
      },

      {
        id: 'collaboration',
        title: 'Real-time Collaboration',
        description: 'Experience collaborative experiment design',
        component: CollaborationStep,
        estimatedDuration: 90,
        required: false,
        prerequisites: ['visual_design']
      },

      {
        id: 'simulation',
        title: 'Test Your Experiment',
        description: 'Use the time-travel simulator to preview your experiment',
        component: SimulationStep,
        estimatedDuration: 60,
        required: true,
        prerequisites: ['visual_design']
      },

      {
        id: 'data_export',
        title: 'Export and Analysis',
        description: 'Generate analysis-ready data and publication materials',
        component: DataExportStep,
        estimatedDuration: 90,
        required: false,
        prerequisites: ['simulation']
      },

      {
        id: 'completion',
        title: 'You\'re Ready!',
        description: 'Start building experiments that will advance science',
        component: CompletionStep,
        estimatedDuration: 30,
        required: true,
        prerequisites: ['simulation']
      }
    ];
  }

  startOnboarding(): void {
    this.userProgress.startOnboarding();
    this.showStep(0);
  }

  private showStep(stepIndex: number): void {
    if (stepIndex >= this.steps.length) {
      this.completeOnboarding();
      return;
    }

    const step = this.steps[stepIndex];
    this.currentStep = stepIndex;

    // Show step component with overlay
    this.renderStepOverlay(step);

    // Track analytics
    this.userProgress.recordStepStart(step.id);
  }

  nextStep(): void {
    const currentStepData = this.steps[this.currentStep];
    this.userProgress.recordStepComplete(currentStepData.id);

    this.showStep(this.currentStep + 1);
  }

  skipStep(): void {
    const currentStepData = this.steps[this.currentStep];
    if (currentStepData.required) {
      // Can't skip required steps
      return;
    }

    this.userProgress.recordStepSkipped(currentStepData.id);
    this.showStep(this.currentStep + 1);
  }
}

