    93→  // Publish experiment to Hub
    94→  async publishExperiment(experiment: CompiledExperiment, metadata: ExperimentMetadata): Promise<HubRepository> {
    95→    // Create repository
    96→    const repo = await this.giteaClient.createRepository({
    97→      name: this.generateRepositoryName(experiment.name),
    98→      description: metadata.description,
    99→      private: metadata.private || false,
   100→      license: 'CC-BY-4.0', // Default for scientific content
   101→      template: 'psyforge-experiment-template'
   102→    });
   103→    
   104→    // Upload experiment files
   105→    await this.uploadExperimentFiles(repo, experiment, metadata);
   106→    
   107→    // Generate DOI if public
   108→    if (!metadata.private) {
   109→      const doi = await this.generateDOI(repo, metadata);
   110→      await this.updateRepositoryMetadata(repo, { doi });
