   118→    const searchQuery = this.buildSearchQuery(criteria);
   119→    const results = await this.giteaClient.searchRepositories(searchQuery);
   120→    
   121→    return results.map(repo => ({
   122→      id: repo.id,
   123→      name: repo.name,
   124→      description: repo.description,
   125→      author: repo.owner.login,
   126→      stars: repo.stars_count,
   127→      forks: repo.forks_count,
   128→      lastUpdated: repo.updated_at,
   129→      tags: this.extractTags(repo.topics),
   130→      doi: this.extractDOI(repo.description),
   131→      citationCount: this.getCitationCount(repo.id)
   132→    }));
   133→  }
