   135→  // Fork experiment for modification
   136→  async forkExperiment(originalId: string, newName?: string): Promise<HubRepository> {
   137→    const fork = await this.giteaClient.forkRepository(originalId, {
   138→      name: newName
   139→    });
   140→    
   141→    // Update fork metadata
