   443→
   444→// Device registry and discovery
   445→export class DeviceRegistry {
   446→  private devices = new Map<string, Device>();
   447→  private drivers = new Map<string, DeviceDriver>();
   448→  
   449→  // Register device driver
   450→  registerDriver(driver: DeviceDriver): void {
   451→    this.drivers.set(driver.deviceType, driver);
   452→  }
   453→  
   454→  // Discover available devices
   455→  async discoverDevices(): Promise<Device[]> {
   456→    const discoveredDevices: Device[] = [];
   457→    
   458→    for (const driver of this.drivers.values()) {
   459→      try {
   460→        const devices = await driver.discover();
   461→        discoveredDevices.push(...devices);
   462→      } catch (error) {
   463→        console.warn(`Device discovery failed for ${driver.deviceType}:`, error);
   464→      }
   465→    }
   466→    
   467→    return discoveredDevices;
   468→  }
   469→  
   470→  // Get device by ID
   471→  getDevice(deviceId: string): Device | undefined {
   472→    return this.devices.get(deviceId);
   473→  }
   474→  
   475→  // Get devices by type
   476→  getDevicesByType<T extends Device>(type: DeviceType): T[] {
   477→    return Array.from(this.devices.values())
   478→      .filter(device => device.deviceType === type) as T[];
   479→  }
   480→}
