   513→
   514→**Virtual Device Implementation:**
   515→```typescript
   516→// @psyforge/dal-virtual
   517→export class VirtualKeyboard implements InputDevice {
   518→  readonly deviceId = 'virtual-keyboard';
   519→  readonly deviceName = 'Virtual Keyboard';
   520→  readonly deviceType = 'input' as const;
   521→  readonly capabilities = {
   522→    hasNumericKeypad: true,
   523→    hasArrowKeys: true,
   524→    hasFunctionKeys: true
   525→  };
   526→  
   527→  private eventEmitter = new EventEmitter();
   528→  private isConnected = false;
   529→  private responseModel: KeyboardResponseModel;
   530→  
   531→  constructor(config: VirtualKeyboardConfig = {}) {
   532→    this.responseModel = new KeyboardResponseModel({
   533→      baseReactionTime: config.baseRT || 350,
   534→      reactionTimeVariability: config.rtVariability || 50,
   535→      errorRate: config.errorRate || 0.02,
   536→      fatigueEffect: config.fatigueEffect || 0.001
   537→    });
   538→  }
   539→  
   540→  async connect(): Promise<void> {
   541→    this.isConnected = true;
   542→    this.emit('connected');
   543→  }
   544→  
   545→  async disconnect(): Promise<void> {
   546→    this.isConnected = false;
   547→    this.emit('disconnected');
   548→  }
   549→  
   550→  // Simulate key press with realistic timing
   551→  simulateKeyPress(key: string, context: ResponseContext = {}): void {
   552→    if (!this.isConnected) return;
   553→    
   554→    const response = this.responseModel.generateResponse(key, context);
   555→    
   556→    // Simulate realistic timing delay
   557→    setTimeout(() => {
   558→      this.emit('keypress', {
   559→        key: response.key,
   560→        timestamp: performance.now(),
   561→        reactionTime: response.reactionTime,
   562→        accuracy: response.accuracy,
   563→        deviceId: this.deviceId
   564→      });
   565→    }, response.reactionTime);
   566→  }
   567→  
   568→  // Auto-response based on stimulus
   569→  autoRespond(stimulus: Stimulus, correctResponse: string): void {
   570→    // Determine if response will be correct based on model
   571→    const shouldRespond = this.responseModel.shouldRespond(stimulus);
   572→    const isCorrect = this.responseModel.isResponseCorrect(stimulus, correctResponse);
   573→    
   574→    if (shouldRespond) {
   575→      const responseKey = isCorrect ? correctResponse : this.responseModel.generateErrorResponse(correctResponse);
   576→      this.simulateKeyPress(responseKey, {
   577→        stimulus,
   578→        correctResponse,
   579→        trialNumber: stimulus.metadata?.trialNumber
   580→      });
   581→    }
   582→  }
   583→  
   584→  // Event handling
   585→  on<T extends DeviceEvent>(event: string, listener: (data: T) => void): this {
   586→    this.eventEmitter.on(event, listener);
   587→    return this;
   588→  }
   589→  
   590→  off(event: string, listener: Function): this {
   591→    this.eventEmitter.off(event, listener);
   592→    return this;
   593→  }
   594→  
   595→  emit(event: string, data: any): void {
   596→    this.eventEmitter.emit(event, data);
   597→  }
   598→}
   599→
   600→// Realistic response modeling
   601→class KeyboardResponseModel {
   602→  constructor(private config: ResponseModelConfig) {}
   603→  
   604→  generateResponse(key: string, context: ResponseContext): SimulatedResponse {
   605→    const baseRT = this.config.baseReactionTime;
   606→    const variability = this.config.reactionTimeVariability;
   607→    const fatigue = this.calculateFatigue(context.trialNumber || 0);
   608→    const practice = this.calculatePracticeEffect(context.trialNumber || 0);
   609→    
   610→    // Generate reaction time from ex-Gaussian distribution
   611→    const reactionTime = this.generateExGaussianRT(baseRT, variability) + fatigue - practice;
   612→    
   613→    // Determine accuracy
   614→    const errorProbability = this.config.errorRate + fatigue * 0.1;
   615→    const accuracy = Math.random() > errorProbability;
   616→    
   617→    return {
   618→      key: accuracy ? key : this.generateErrorKey(key),
   619→      reactionTime: Math.max(reactionTime, 100), // Minimum 100ms RT
   620→      accuracy
   621→    };
   622→  }
   623→  
   624→  private generateExGaussianRT(mu: number, sigma: number, tau: number = 50): number {
   625→    // Ex-Gaussian distribution: normal + exponential
   626→    const normal = this.randomNormal(mu, sigma);
   627→    const exponential = -tau * Math.log(Math.random());
   628→    return normal + exponential;
   629→  }
   630→  
   631→  private randomNormal(mean: number, stdDev: number): number {
   632→    // Box-Muller transform
   633→    const u1 = Math.random();
   634→    const u2 = Math.random();
   635→    const z0 = Math.sqrt(-2 * Math.log(u1)) * Math.cos(2 * Math.PI * u2);
   636→    return z0 * stdDev + mean;
   637→  }
   638→}
   639→```
