   731→      min: 0.1,
   732→      max: 0.9,
   733→      description: 'Proportion of congruent trials (0.5 = equal congruent/incongruent)'
   734→    }
   735→  },
   736→  
   737→  generate(params: StroopParameters): CompiledExperiment {
   738→    const colors = ['red', 'green', 'blue', 'yellow'];
   739→    const words = ['RED', 'GREEN', 'BLUE', 'YELLOW'];
   740→    const keys = ['r', 'g', 'b', 'y'];
   741→    
   742→    return new Experiment({ name: 'Stroop Task' })
   743→      .addTimeline(
   744→        new Timeline({ id: 'instructions' })
   745→          .addTrial(createInstructionTrial())
   746→      )
   747→      .addTimeline(
   748→        new Timeline({ id: 'practice' })
   749→          .addTrials(generateStroopTrials({
   750→            colors, words, keys,
   751→            nTrials: params.practiceTrials,
   752→            congruentProp: 0.5, // Balanced practice
   753→            stimulusDuration: params.stimulusDuration,
   754→            responseTimeout: params.responseTimeout
   755→          }))
   756→          .setRandomization({ method: 'shuffle' })
   757→      )
   758→      .addTimeline(
   759→        new Timeline({ id: 'main_experiment' })
   760→          .addTrials(generateStroopTrials({
   761→            colors, words, keys,
   762→            nTrials: params.testTrials,
   763→            congruentProp: params.congruentProportion,
   764→            stimulusDuration: params.stimulusDuration,
   765→            responseTimeout: params.responseTimeout
   766→          }))
   767→          .setRandomization({ method: 'shuffle', constraints: ['no_more_than_3_consecutive'] })
   768→      )
   769→      .requirePower({ effect: 0.7, alpha: 0.05, target: 0.8 })
   770→      .compile();
   771→  }
   772→});
   773→
   774→// Register paradigm in library
   775→ParadigmLibrary.register('stroop-task', StroopTask);
   776→```
   777→
   778→#### EGS-002: Begin "100-in-100" Sprint: Port 10 Paradigms
