### Epic: Device Abstraction Layer (DAL)
**Story Points: 7**

#### DAL-001: Finalize DAL Interfaces
**Points: 3 | Priority: Critical**

**Description:** Define the standard interfaces for device integration that will support the ecosystem.

**Technical Requirements:**
- TypeScript interfaces for all major device categories
- Plugin architecture for third-party device drivers
- Event-driven architecture for real-time device communication
- Device capability discovery and validation
- Cross-platform compatibility (web, desktop, mobile)

**Acceptance Criteria:**
- [ ] Complete interface definitions for input, output, and physiological devices
- [ ] Plugin system allows third-party driver development
- [ ] Device discovery automatically detects available hardware
- [ ] Event system handles real-time device communication efficiently
- [ ] Interface design supports both web and native implementations

**DAL Interface Design:**
```typescript
// @psyforge/dal
export interface Device {
  readonly deviceId: string;
  readonly deviceName: string;
  readonly deviceType: DeviceType;
  readonly capabilities: DeviceCapabilities;
  readonly isConnected: boolean;

  // Lifecycle methods
  connect(): Promise<void>;
  disconnect(): Promise<void>;
  calibrate?(): Promise<CalibrationResult>;

  // Event handling
  on<T extends DeviceEvent>(event: string, listener: (data: T) => void): this;
  off(event: string, listener: Function): this;
  emit(event: string, data: any): void;

  // Device status
  getStatus(): DeviceStatus;
  getCapabilities(): DeviceCapabilities;
}

// Input devices (keyboards, mice, response boxes)
export interface InputDevice extends Device {
  readonly deviceType: 'input';

  // Common input events
  on(event: 'keypress', listener: (data: KeyPressEvent) => void): this;
  on(event: 'buttonpress', listener: (data: ButtonPressEvent) => void): this;
  on(event: 'mouseclick', listener: (data: MouseClickEvent) => void): this;
}

// Physiological monitoring devices
export interface PhysiologicalDevice extends Device {
  readonly deviceType: 'physiological';
  readonly samplingRate: number;

  startRecording(): Promise<void>;
  stopRecording(): Promise<RecordingData>;

  on(event: 'sample', listener: (data: PhysiologicalSample) => void): this;
  on(event: 'artifact', listener: (data: ArtifactEvent) => void): this;
}

// EEG-specific interface
export interface EEGDevice extends PhysiologicalDevice {
  readonly channels: number;
  readonly impedanceThreshold: number;

  checkImpedance(): Promise<ImpedanceReadings>;
  setReference(reference: EEGReference): Promise<void>;
  sendTrigger(code: number, timestamp?: number): Promise<void>;
}

// Eye tracking interface
export interface EyeTracker extends PhysiologicalDevice {
  readonly trackingMode: 'monocular' | 'binocular';
  readonly accuracy: number; // degrees visual angle

  calibrate(points: CalibrationPoint[]): Promise<CalibrationResult>;
  startValidation(): Promise<ValidationResult>;

  on(event: 'gaze', listener: (data: GazeEvent) => void): this;
  on(event: 'fixation', listener: (data: FixationEvent) => void): this;
  on(event: 'saccade', listener: (data: SaccadeEvent) => void): this;
}

// Response box interface (Cedrus, Psychology Software Tools)
export interface ResponseBox extends InputDevice {
  readonly buttonCount: number;
  readonly hasLights: boolean;

  setButtonLight(button: number, state: boolean): Promise<void>;

  on(event: 'buttonpress', listener: (data: ButtonPressEvent) => void): this;
  on(event: 'buttonrelease', listener: (data: ButtonReleaseEvent) => void): this;
}

// Device registry and discovery
export class DeviceRegistry {
  private devices = new Map<string, Device>();
  private drivers = new Map<string, DeviceDriver>();

  // Register device driver
  registerDriver(driver: DeviceDriver): void {
    this.drivers.set(driver.deviceType, driver);
  }

  // Discover available devices
  async discoverDevices(): Promise<Device[]> {
    const discoveredDevices: Device[] = [];

    for (const driver of this.drivers.values()) {
      try {
        const devices = await driver.discover();
        discoveredDevices.push(...devices);
      } catch (error) {
        console.warn(`Device discovery failed for ${driver.deviceType}:`, error);
      }
    }

    return discoveredDevices;
  }

  // Get device by ID
  getDevice(deviceId: string): Device | undefined {
    return this.devices.get(deviceId);
  }

  // Get devices by type
  getDevicesByType<T extends Device>(type: DeviceType): T[] {
    return Array.from(this.devices.values())
      .filter(device => device.deviceType === type) as T[];
  }
}

export interface DeviceDriver {
  readonly deviceType: string;
  readonly supportedModels: string[];

  // Discover devices of this type
  discover(): Promise<Device[]>;

  // Create device instance
  createDevice(config: DeviceConfig): Promise<Device>;
}
```

#### DAL-002: Virtual Device Lab & Keyboard Driver
**Points: 4 | Priority: High**

**Description:** Build the virtual device simulation environment and implement the first real device driver.

**Technical Requirements:**
- Virtual devices that simulate real hardware behavior
- Configurable response patterns and timing characteristics
- Integration with time-travel simulator for predictable testing
- Reference keyboard driver implementation
- Device testing framework for validation

**Acceptance Criteria:**
- [ ] Virtual keyboard provides realistic key press simulation
- [ ] Virtual response box simulates button timing and lighting
- [ ] Virtual eye tracker generates realistic gaze patterns
- [ ] Physical keyboard driver works across operating systems
- [ ] Device testing framework validates driver implementations
- [ ] Virtual devices integrate with experiment simulation

**Virtual Device Implementation:**
```typescript
// @psyforge/dal-virtual
export class VirtualKeyboard implements InputDevice {
  readonly deviceId = 'virtual-keyboard';
  readonly deviceName = 'Virtual Keyboard';
  readonly deviceType = 'input' as const;
  readonly capabilities = {
    hasNumericKeypad: true,
    hasArrowKeys: true,
    hasFunctionKeys: true
  };

  private eventEmitter = new EventEmitter();
  private isConnected = false;
  private responseModel: KeyboardResponseModel;

  constructor(config: VirtualKeyboardConfig = {}) {
    this.responseModel = new KeyboardResponseModel({
      baseReactionTime: config.baseRT || 350,
      reactionTimeVariability: config.rtVariability || 50,
      errorRate: config.errorRate || 0.02,
      fatigueEffect: config.fatigueEffect || 0.001
    });
  }

  async connect(): Promise<void> {
    this.isConnected = true;
    this.emit('connected');
  }

  async disconnect(): Promise<void> {
    this.isConnected = false;
    this.emit('disconnected');
  }

  // Simulate key press with realistic timing
  simulateKeyPress(key: string, context: ResponseContext = {}): void {
    if (!this.isConnected) return;

    const response = this.responseModel.generateResponse(key, context);

    // Simulate realistic timing delay
    setTimeout(() => {
      this.emit('keypress', {
        key: response.key,
        timestamp: performance.now(),
        reactionTime: response.reactionTime,
        accuracy: response.accuracy,
        deviceId: this.deviceId
      });
    }, response.reactionTime);
  }

  // Auto-response based on stimulus
  autoRespond(stimulus: Stimulus, correctResponse: string): void {
    // Determine if response will be correct based on model
    const shouldRespond = this.responseModel.shouldRespond(stimulus);
    const isCorrect = this.responseModel.isResponseCorrect(stimulus, correctResponse);

    if (shouldRespond) {
      const responseKey = isCorrect ? correctResponse : this.responseModel.generateErrorResponse(correctResponse);
      this.simulateKeyPress(responseKey, {
        stimulus,
        correctResponse,
        trialNumber: stimulus.metadata?.trialNumber
      });
    }
  }

  // Event handling
  on<T extends DeviceEvent>(event: string, listener: (data: T) => void): this {
    this.eventEmitter.on(event, listener);
    return this;
  }

  off(event: string, listener: Function): this {
    this.eventEmitter.off(event, listener);
    return this;
  }

  emit(event: string, data: any): void {
    this.eventEmitter.emit(event, data);
  }
}

// Realistic response modeling
class KeyboardResponseModel {
  constructor(private config: ResponseModelConfig) {}

  generateResponse(key: string, context: ResponseContext): SimulatedResponse {
    const baseRT = this.config.baseReactionTime;
    const variability = this.config.reactionTimeVariability;
    const fatigue = this.calculateFatigue(context.trialNumber || 0);
    const practice = this.calculatePracticeEffect(context.trialNumber || 0);

    // Generate reaction time from ex-Gaussian distribution
    const reactionTime = this.generateExGaussianRT(baseRT, variability) + fatigue - practice;

    // Determine accuracy
    const errorProbability = this.config.errorRate + fatigue * 0.1;
    const accuracy = Math.random() > errorProbability;

    return {
      key: accuracy ? key : this.generateErrorKey(key),
      reactionTime: Math.max(reactionTime, 100), // Minimum 100ms RT
      accuracy
    };
  }

  private generateExGaussianRT(mu: number, sigma: number, tau: number = 50): number {
    // Ex-Gaussian distribution: normal + exponential
    const normal = this.randomNormal(mu, sigma);
    const exponential = -tau * Math.log(Math.random());
    return normal + exponential;
  }

  private randomNormal(mean: number, stdDev: number): number {
    // Box-Muller transform
    const u1 = Math.random();
    const u2 = Math.random();
    const z0 = Math.sqrt(-2 * Math.log(u1)) * Math.cos(2 * Math.PI * u2);
    return z0 * stdDev + mean;
  }
}
```

