// Core device abstractions
export { Device } from './Device.js';
export type { DeviceCapabilities, DeviceEvent } from './Device.js';
export { DeviceManager } from './DeviceManager.js';
export type { DeviceManagerOptions, DeviceType } from './DeviceManager.js';

// Input devices
export { KeyboardDevice } from './KeyboardDevice.js';
export type { KeyboardEventData } from './KeyboardDevice.js';
export { MouseDevice } from './MouseDevice.js';
export type { MouseEventData } from './MouseDevice.js';
export { TouchDevice } from './TouchDevice.js';
export type {
  TouchEventData,
  TouchPoint,
  OrientationEventData,
} from './TouchDevice.js';

// Audio/video devices
export { AudioDevice } from './AudioDevice.js';
export type { AudioDeviceInfo, AudioEventData } from './AudioDevice.js';
export { VideoDevice } from './VideoDevice.js';
export type { VideoDeviceInfo, VideoEventData } from './VideoDevice.js';

// Import types for internal use
import { Device } from './Device.js';
import { DeviceManager, DeviceManagerOptions } from './DeviceManager.js';
import { KeyboardDevice } from './KeyboardDevice.js';
import { MouseDevice } from './MouseDevice.js';
import { TouchDevice } from './TouchDevice.js';
import { AudioDevice } from './AudioDevice.js';
import { VideoDevice } from './VideoDevice.js';

// Helper functions for common device management patterns
export function createDeviceManager(
  clock: import('@psyforge/timing').PrecisionClock,
  options?: DeviceManagerOptions,
): DeviceManager {
  return new DeviceManager(clock, options);
}

export async function detectDeviceCapabilities(
  clock: import('@psyforge/timing').PrecisionClock,
): Promise<{
  keyboard: boolean;
  mouse: boolean;
  touch: boolean;
  audio: boolean;
  video: boolean;
}> {
  const manager = createDeviceManager(clock, { enableAutoDetection: false });
  return await manager.detectAvailableDevices();
}

// Type guards for device instances
export function isKeyboardDevice(device: Device): device is KeyboardDevice {
  return device.deviceType === 'keyboard';
}

export function isMouseDevice(device: Device): device is MouseDevice {
  return device.deviceType === 'mouse';
}

export function isTouchDevice(device: Device): device is TouchDevice {
  return device.deviceType === 'touch';
}

export function isAudioDevice(device: Device): device is AudioDevice {
  return device.deviceType === 'audio';
}

export function isVideoDevice(device: Device): device is VideoDevice {
  return device.deviceType === 'video';
}

/**
 * @psyforge/scheduler - Hierarchical task scheduler for precise experiment execution
 * 
 * Provides frame-accurate timing control, priority-based scheduling, and
 * hierarchical timeline management for behavioral research experiments.
 */

// Core scheduler
export { Scheduler, type SchedulerOptions, type SchedulerMetrics } from './Scheduler.js';
import { Scheduler, type SchedulerOptions } from './Scheduler.js';

// Task management
export { 
  Task, 
  TaskState,
  type TaskContext, 
  type TaskFunction, 
  type TaskCompletionCallback,
  type TaskOptions 
} from './Task.js';
import { Task, type TaskFunction, type TaskOptions } from './Task.js';

// Priority system
export { TaskPriority, TaskPriorityUtils } from './TaskPriority.js';
import { TaskPriority } from './TaskPriority.js';

// Timeline hierarchy
export { 
  Timeline, 
  TimelineState,
  type TimelineEvent, 
  type TimelineOptions 
} from './Timeline.js';
import { Timeline, type TimelineOptions } from './Timeline.js';

/**
 * Create a new scheduler instance with default configuration
 * optimized for psychological experiments
 */
export function createScheduler(options: SchedulerOptions = {}): Scheduler {
  return new Scheduler({
    maxTasksPerFrame: 10,
    frameTimeBudget: 8, // 8ms for 120fps headroom
    useHighPrecisionTiming: true,
    timingTolerance: 2, // 2ms tolerance for ≤2ms target
    allowPreemption: true,
    ...options
  });
}

/**
 * Create a new timeline with experiment-friendly defaults
 */
export function createTimeline(name: string, options: Omit<TimelineOptions, 'name'> = {}): Timeline {
  return new Timeline({
    name,
    defaultPriority: TaskPriority.NORMAL,
    repeatable: false,
    repetitions: 1,
    ...options
  });
}

/**
 * Create a repeating timeline for trial-based experiments
 */
export function createTrialTimeline(
  name: string, 
  repetitions: number, 
  repetitionDelay: number = 0,
  options: Omit<TimelineOptions, 'name' | 'repeatable' | 'repetitions' | 'repetitionDelay'> = {}
): Timeline {
  return new Timeline({
    name,
    repeatable: true,
    repetitions,
    repetitionDelay,
    defaultPriority: TaskPriority.NORMAL,
    ...options
  });
}

/**
 * Helper to create a task with common experiment patterns
 */
export function createTask(
  name: string,
  execute: TaskFunction,
  priority: TaskPriority = TaskPriority.NORMAL,
  options: Omit<TaskOptions, 'priority'> = {}
): Task {
  return new Task(name, execute, { priority, ...options });
}

/**
 * Helper to create a stimulus presentation task
 */
export function createStimulusTask(
  name: string,
  stimulusFunction: TaskFunction,
  options: TaskOptions = {}
): Task {
  return new Task(name, stimulusFunction, {
    priority: TaskPriority.HIGH, // Stimulus presentation is high priority
    timeout: 10000, // 10 second timeout for stimuli
    interruptible: false, // Don't interrupt stimulus presentation
    ...options
  });
}

/**
 * Helper to create a response collection task
 */
export function createResponseTask(
  name: string,
  responseFunction: TaskFunction,
  timeoutMs: number = 5000,
  options: Omit<TaskOptions, 'timeout' | 'priority'> = {}
): Task {
  return new Task(name, responseFunction, {
    priority: TaskPriority.CRITICAL, // Response collection is critical
    timeout: timeoutMs,
    interruptible: true, // Can be interrupted by timeout
    ...options
  });
}

/**
 * Version information
 */
export const VERSION = '0.1.0';

// Note: Default export removed to avoid circular reference issues in tests

