          .fadeIn(150)
          .duration(500)
          .fadeOut(150)
          .build()
      )
      // Precise response window
      .add(
        forge.response()
          .keyboard()
          .keys(' ') // Spacebar for match
          .timeout(1500)
          .onResponse((response) => {
            const isMatch = item.isMatch;
            const responded = response.key === ' ';
            const correct = (isMatch && responded) || (!isMatch && !responded);

            console.log(`N-Back Trial ${index + 1}:`, {
              stimulus: item.stimulus,
              position: item.position,
              isMatch,
              responded,
              correct,
              reactionTime: response.reactionTime,
            });
          })
          .build()
      );

    experiment.addTrial(trial.build());
  });

  await experiment.run();
  console.log('✅ Revolutionary N-Back experiment completed!');
}

// 👁️ VISUAL SEARCH REVOLUTION
export async function revolutionaryVisualSearch() {
  console.log('👁️ Running Revolutionary Visual Search...');

  const forge = await createComponentForge({
    container: '#experiment-container',
    enableGPUAcceleration: true,
    enableMetrics: true,
    maxFrameTime: 2,
    targetFPS: 144,
  });

  const experiment = forge.experiment('Revolutionary Visual Search')
    .description('GPU-accelerated visual search with complex displays')
    .author('ComponentForge Vision Team');

  // Create complex visual displays
  const searchTrials = generateVisualSearchTrials(10);

  searchTrials.forEach((searchTrial, index) => {
    const trial = forge.trial(`search_${index}`);

    // Create circular layout for search items
    const searchLayout = forge.layout()
      .circle(200)
      .spacing(45); // 45 degrees between items

    // Add search items with different properties
    searchTrial.items.forEach((item, itemIndex) => {
      const text = forge.text(item.shape)
        .fontSize(32)
        .color(item.color)
        .build();

      searchLayout.add(text);
    });

    trial
      .add(searchLayout.build())
      .add(
        forge.response()
          .keyboard()
          .keys('y', 'n') // Yes/No for target present
          .timeout(5000)
          .onResponse((response) => {
            const correct = (searchTrial.targetPresent && response.key === 'y') ||
                           (!searchTrial.targetPresent && response.key === 'n');

            console.log(`Visual Search Trial ${index + 1}:`, {
              targetPresent: searchTrial.targetPresent,
              response: response.key,
              correct,
              reactionTime: response.reactionTime,
              setSize: searchTrial.items.length,
            });
          })
          .build()
      );

    experiment.addTrial(trial.build());
  });

  await experiment.run();
  console.log('✅ Revolutionary Visual Search experiment completed!');
}

// 🎨 COMPONENT COMPOSITION DEMO
export async function componentCompositionDemo() {
  console.log('🎨 Running Component Composition Demo...');

  const forge = await createComponentForge({
    container: '#experiment-container',
    enableGPUAcceleration: true,
    enableMetrics: true,
    maxFrameTime: 2,
  });

  // Demonstrate advanced component composition
  const demo = forge.trial('composition_demo');

  // Create a complex layout with nested components
  const mainLayout = forge.layout()
    .grid(3, 3)
    .spacing(100, 100);

  // Grid of animated text components
  for (let i = 0; i < 9; i++) {
    const text = forge.text(`${i + 1}`)
      .fontSize(48)
      .color(`hsl(${i * 40}, 70%, 50%)`)
      .fadeIn(200 + i * 100)
      .build();

    // Add bounce animation with different timing
    const animation = forge.animate(text)
      .bounce(20, 800 + i * 100)
      .build();

    mainLayout.add(text);
    demo.add(animation);
  }

  demo.add(mainLayout.build());

  // Response to end demo
  demo.add(
    forge.response()
      .keyboard()
      .keys(' ')
      .timeout(10000)
      .build()
  );

  await demo.run();
  console.log('✅ Component Composition Demo completed!');
}

// 🎯 MASTER DEMO - Run all revolutionary experiments
export async function runRevolutionaryDemo() {
  console.log('🎯 Running Complete Revolutionary Demo...');

  try {
    console.log('\n=== ComponentForge Revolutionary Features ===');
    console.log('• GPU-accelerated component rendering');
    console.log('• μs-level timing precision');
    console.log('• Composable component architecture'); 
    console.log('• Real-time performance monitoring');
    console.log('• Advanced animations and effects');
    console.log('• Fluent experiment definition API');

    console.log('\n🚀 Starting Revolutionary Experiments...\n');

    await revolutionaryStroopTask();
    console.log('\n' + '='.repeat(50) + '\n');

    await revolutionaryNBackTask();
    console.log('\n' + '='.repeat(50) + '\n');

    await revolutionaryVisualSearch();
    console.log('\n' + '='.repeat(50) + '\n');

    await componentCompositionDemo();

    console.log('\n🎯 REVOLUTIONARY DEMO COMPLETE!');
    console.log('This is the future of psychological experimentation.');

  } catch (error) {
    console.error('Demo error:', error);
  }
}

// Helper functions
function generateNBackSequence(n: number, trials: number) {
  const stimuli = ['A', 'B', 'C', 'D', 'E'];
  const positions = [
    { x: -100, y: -100 }, { x: 0, y: -100 }, { x: 100, y: -100 },
    { x: -100, y: 0 },    { x: 0, y: 0 },    { x: 100, y: 0 },
    { x: -100, y: 100 },  { x: 0, y: 100 },  { x: 100, y: 100 }
  ];

  const sequence = [];

  for (let i = 0; i < trials; i++) {
    const stimulus = stimuli[Math.floor(Math.random() * stimuli.length)];
    const position = positions[Math.floor(Math.random() * positions.length)];
    const isMatch = i >= n && (
      sequence[i - n].stimulus === stimulus || 
      sequence[i - n].position === position
    );

    sequence.push({ stimulus, position, isMatch });
  }

  return sequence;
}

function generateVisualSearchTrials(count: number) {
  const shapes = ['●', '■', '▲', '◆'];
  const colors = ['red', 'green', 'blue', 'orange'];

  return Array(count).fill(null).map((_, index) => {
    const setSize = 4 + Math.floor(Math.random() * 8); // 4-12 items
    const targetPresent = Math.random() > 0.5;
    const targetShape = shapes[0]; // Circle is target
    const targetColor = colors[0]; // Red is target

    const items = [];

    if (targetPresent) {
      items.push({ shape: targetShape, color: targetColor });
    }

    // Add distractors
    while (items.length < setSize) {
      const shape = shapes[Math.floor(Math.random() * shapes.length)];
      const color = colors[Math.floor(Math.random() * colors.length)];

      // Avoid creating target by accident
      if (!(shape === targetShape && color === targetColor)) {
        items.push({ shape, color });
      }
    }

    // Shuffle items
    for (let i = items.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [items[i], items[j]] = [items[j], items[i]];
    }

    return { items, targetPresent };
  });
}

export default {
  revolutionaryStroopTask,
  revolutionaryNBackTask,
  revolutionaryVisualSearch,
  componentCompositionDemo,
  runRevolutionaryDemo,
};

