**WebGL2 Architecture:**
```typescript
class ExperimentPreviewRenderer {
  private gl: WebGL2RenderingContext;
  private componentRenderer: ComponentRenderer;
  private performanceProfiler: PerformanceProfiler;

  async initializeWebGL2(canvas: HTMLCanvasElement): Promise<void> {
    this.gl = canvas.getContext('webgl2')!;

    if (!this.gl) {
      throw new Error('WebGL2 not supported');
    }

    await this.setupShaders();
    await this.initializeBuffers();
    this.enablePerformanceMonitoring();
  }

  renderExperiment(experiment: Experiment): void {
    const frameStart = performance.now();

    this.gl.clear(this.gl.COLOR_BUFFER_BIT | this.gl.DEPTH_BUFFER_BIT);

    // Render all components with GPU acceleration
    for (const component of experiment.getAllComponents()) {
      this.componentRenderer.render(component);
    }

    const frameTime = performance.now() - frameStart;
    this.performanceProfiler.recordFrame(frameTime);

    if (frameTime > 2) {
      console.warn(`Frame time exceeded 2ms: ${frameTime.toFixed(3)}ms`);
    }
  }
}
```

